import React, {useMemo, useRef} from "react";

import type {IKitsRadioProps} from "@lmb-it/kitsconcerto-types";
import {Flex, KitsContainer} from "../../../";

import {useSelectionController} from "../../../../../Hooks";
import RadioButton from "./radiobutton";

const KitsRadio = <T, >({
                            id,
                            label,
                            required,
                            errors,
                            hideError,
                            isFloatedLabel,
                            helperText,
                            item,
                            value,
                            defaultValue,
                            onChange,
                            appearanceMode = "vertical",
                            disabled,
                            invalid,
                            containerStyle
                        }: IKitsRadioProps<T>) => {
    const items = useMemo(
        () => (Array.isArray(item) ? item : [item]),
        [item]
    );

    const lastToggledIndex = useRef<number | null>(null);

    const controller = useSelectionController<T>({
        mode: "single",
        value,
        defaultValue,
        onChange: (selectedValue) => {
            const index = lastToggledIndex.current;
            if (index == null) return;

            const currentItem = items[index];

            if (currentItem)
                onChange?.(selectedValue === currentItem?.value, {
                    item: currentItem,
                    index,
                    value: currentItem.value,
                });
        },
    });
    const direction = appearanceMode === "horizontal" ? "row" : "column";

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
            containerStyle={{borderRadius:0, overflow:"visible", ...containerStyle, borderWidth:0}}
        >
            <Flex flexDirection={direction} gap={10}>
                {items.map((it, index) => {
                    const selected = controller.isSelected(it);

                    return (
                        <RadioButton<T>
                            key={String(it.value)}
                            item={it}
                            selected={selected}
                            disabled={disabled}
                            isInvalid={invalid}
                            onToggle={() => {
                                lastToggledIndex.current = index;
                                controller.onChange(it);
                            }}
                        />
                    );
                })}
            </Flex>

        </KitsContainer>
    );
};

export default KitsRadio;
